const token = env.get('AXIOM_MONITORING_TOKEN') || env.get('AXIOM_API_TOKEN');
if (!token) {
  node.error('AXIOM_MONITORING_TOKEN is required for Axiom monitor polling', msg);
  return null;
}

const defaultIds = [
  'nqTSos0T5yFVk5ddpg', // MoltNet auth/client noise by status
  'lmBV3iwC8xKRBFnDCi', // MoltNet event loop pressure by service
  'DaoHjCgByMCE6JLTm8', // MoltNet MCP server 5xx by route
  'mc6I3pddWkPzIHG1gb', // MoltNet heap pressure by service
  'ULZWyXD6wmvVbwFmMY', // MoltNet request latency p95 by service
  'a15YiYDnMct15XeAVJ'  // MoltNet REST API 5xx by route
];
const ids = String(env.get('AXIOM_MONITOR_IDS') || '')
  .split(',')
  .map((id) => id.trim())
  .filter(Boolean);
const monitorIds = ids.length ? ids : defaultIds;
const lookbackMinutes = Number(env.get('AXIOM_POLL_WINDOW_MINUTES') || 15);
const end = new Date();
const start = new Date(end.getTime() - lookbackMinutes * 60 * 1000);

for (const monitorId of monitorIds) {
  const out = { ...msg };
  out.method = 'GET';
  out.url = 'https://api.axiom.co/v2/monitors/' + encodeURIComponent(monitorId) + '/history?startTime=' + encodeURIComponent(start.toISOString()) + '&endTime=' + encodeURIComponent(end.toISOString());
  out.headers = { Authorization: 'Bearer ' + token };
  out.axiomPoll = {
    monitorId,
    window: { start: start.toISOString(), end: end.toISOString() }
  };
  node.send(out);
}
return null;

const events = Array.isArray(msg.payload) ? msg.payload : [];
const seen = flow.get('axiomSeenMonitorEvents') || {};
const now = Date.now();
const maxAgeMs = 24 * 60 * 60 * 1000;
for (const [key, value] of Object.entries(seen)) {
  if (now - Number(value) > maxAgeMs) delete seen[key];
}

for (const event of events) {
  const monitorId = event.checkId || msg.axiomPoll?.monitorId || 'unknown-monitor';
  const state = String(event.state || '').toLowerCase();
  const timestamp = event.timestamp || new Date().toISOString();
  const dedupeKey = [monitorId, state || 'unknown', timestamp].join('|');
  if (seen[dedupeKey]) continue;
  seen[dedupeKey] = now;

  const name = String(event.name || 'Axiom monitor alert');
  const action = state === 'open' || /^triggered:/i.test(name) ? 'triggered' : state === 'closed' || /^resolved:/i.test(name) ? 'resolved' : state || 'unknown';
  const monitorName = name.replace(/^(Triggered|Resolved):\s*/i, '') || 'Axiom monitor alert';
  const triggerLike = action === 'triggered' || action === 'open' || action === 'firing';

  const out = { ...msg };
  out.axiom = {
    raw: event,
    action,
    triggerLike,
    monitorId,
    monitorName,
    service: null,
    route: null,
    severity: 'unknown',
    startedAt: timestamp,
    window: msg.axiomPoll?.window || { start: 'now-15m', end: 'now' },
    datasets: { traces: 'moltnet', metrics: 'moltnet-metrics' },
    repo: { owner: 'getlarge', name: 'themoltnet' },
    source: 'axiom-monitor-history'
  };
  node.send(out);
}
flow.set('axiomSeenMonitorEvents', seen);
return null;

function respond(statusCode, payload) {
  msg.statusCode = statusCode;
  msg.payload = payload;
  return [msg, null];
}

const headerSecret = msg.req?.headers?.['x-axiom-webhook-secret'];
const expectedSecret = env.get('AXIOM_WEBHOOK_SECRET');
if (expectedSecret && headerSecret !== expectedSecret) {
  return respond(401, { ok: false, error: 'invalid webhook secret' });
}

let payload = msg.payload;
if (typeof payload === 'string') {
  try {
    payload = JSON.parse(payload);
  } catch (err) {
    return respond(400, { ok: false, error: 'invalid JSON payload' });
  }
}

const action = String(payload?.action || payload?.Action || payload?.state || payload?.State || '').toLowerCase();
const monitorId = payload?.monitorId || payload?.MonitorID || payload?.monitor_id || payload?.id || payload?.ID || 'unknown-monitor';
const monitorName = payload?.monitorName || payload?.MonitorName || payload?.name || payload?.Title || 'Axiom monitor alert';
const service = payload?.service || payload?.serviceName || payload?.['service.name'] || payload?.Service || null;
const route = payload?.route || payload?.httpRoute || payload?.['attributes.route'] || null;
const severity = payload?.severity || payload?.Severity || payload?.priority || 'unknown';
const startedAt = payload?.startedAt || payload?.timestamp || payload?.Timestamp || new Date().toISOString();
const start = payload?.startTime || payload?.StartTime || 'now-30m';
const end = payload?.endTime || payload?.EndTime || 'now';

const triggerLike = !action || ['trigger', 'triggered', 'open', 'alert', 'firing'].includes(action);
msg.axiom = {
  raw: payload,
  action: action || 'unknown',
  triggerLike,
  monitorId,
  monitorName,
  service,
  route,
  severity,
  startedAt,
  window: { start, end },
  datasets: { traces: 'moltnet', metrics: 'moltnet-metrics' },
  repo: { owner: 'getlarge', name: 'themoltnet' }
};

const ack = {
  ...msg,
  statusCode: 202,
  payload: {
    ok: true,
    accepted: triggerLike,
    monitorId,
    monitorName,
    action: msg.axiom.action
  }
};
return [ack, msg];

const alert = msg.axiom;
const brief = [
  'Use the axiom-alert-triage skill.',
  'You are the parser/enricher for an Axiom monitor alert.',
  'Classify the alert family, choose the relevant Axiom API surfaces, query correlated logs/traces/metrics, and produce a JSON artifact titled telemetry-evidence.',
  'Use the alert context attached to this task. Do not inspect the codebase yet unless needed to choose query dimensions. Do not mutate Axiom config.',
  '',
  'Artifact requirements:',
  '- title: telemetry-evidence',
  '- kind: json',
  '- include monitor id/name/action/severity/window',
  '- include exact APL/MPL query text and result summaries',
  '- include correlated traceIds/taskIds/teamIds/diaryIds when present',
  '- include gaps and confidence'
].join('\n');

msg.payload = {
  taskType: 'freeform',
  title: 'Axiom alert evidence: ' + alert.monitorName,
  tags: ['axiom-alert', 'telemetry-evidence', alert.monitorId],
  input: { brief }
};
return msg;

const evidence = msg.result?.artifactBody || null;
const artifactRef = msg.result?.artifactRef;
const outputRef = msg.result?.outputRef;
if (!artifactRef && !outputRef) {
  node.error('Parser task did not produce an artifactRef or outputRef', msg);
  return null;
}
const alert = msg.axiom || {};
msg.telemetryEvidence = evidence;
msg.telemetryEvidenceRef = artifactRef || outputRef;
const brief = [
  'Use the axiom-alert-triage skill.',
  'You are the codebase triage agent for an Axiom alert in getlarge/themoltnet.',
  'Consume the referenced telemetry-evidence artifact. Query Axiom again only if the evidence has gaps that block a concrete conclusion.',
  'Compare findings with the MoltNet codebase, open GitHub issues, and MoltNet diary entries. Do not patch code and do not mutate Axiom config.',
  '',
  'Produce a JSON artifact titled triage-report with verdict, evidence, suspectedSubsystems, codeReferences, relatedIssues, relatedEntries, recommendedAction, confidence, and gaps.'
].join('\n');

msg.payload = {
  taskType: 'freeform',
  title: 'Axiom alert codebase triage: ' + (alert.monitorName || 'unknown monitor'),
  tags: ['axiom-alert', 'codebase-triage', alert.monitorId || 'unknown-monitor'],
  input: { brief }
};
return msg;

const report = msg.result?.artifactBody || null;
const artifactRef = msg.result?.artifactRef;
const outputRef = msg.result?.outputRef;
if (!artifactRef && !outputRef) {
  node.error('Triage task did not produce an artifactRef or outputRef', msg);
  return null;
}
const alert = msg.axiom || {};
msg.triageReport = report;
msg.triageReportRef = artifactRef || outputRef;
const brief = [
  'Use the axiom-alert-triage skill.',
  'You are the judge for an Axiom alert triage report.',
  'Review the referenced triage-report artifact and decide whether the analysis is actionable, needs revision, or should be treated as monitor noise.',
  'Do not patch code, mutate Axiom config, or create GitHub issues.',
  '',
  'Judge rubric:',
  '- report cites telemetry evidence',
  '- code references exist for actionable code hypotheses',
  '- severity uses monitor threshold/value/window context',
  '- related GitHub issues and MoltNet entries were checked when tooling was available',
  '- recommended action is concrete',
  '',
  'Produce a JSON artifact titled triage-judgment with verdict pass|revise|noise, reasons, missingEvidence, and nextAction.'
].join('\n');

msg.payload = {
  taskType: 'freeform',
  title: 'Judge Axiom alert triage: ' + (alert.monitorName || 'unknown monitor'),
  tags: ['axiom-alert', 'triage-judge', alert.monitorId || 'unknown-monitor'],
  input: { brief }
};
return msg;

const now = new Date();
const start = new Date(now.getTime() - 15 * 60 * 1000);
msg.axiom = {
  raw: {
    synthetic: true,
    reason: 'manual Node-RED smoke test',
    generatedAt: now.toISOString()
  },
  action: 'triggered',
  triggerLike: true,
  monitorId: 'synthetic-node-red-smoke-test',
  monitorName: 'Synthetic Node-RED triage smoke test',
  service: 'moltnet-rest-api',
  route: '/synthetic/node-red-smoke-test',
  severity: 'test',
  startedAt: now.toISOString(),
  window: { start: start.toISOString(), end: now.toISOString() },
  datasets: { traces: 'moltnet', metrics: 'moltnet-metrics' },
  repo: { owner: 'getlarge', name: 'themoltnet' },
  source: 'synthetic-node-red-inject',
  synthetic: true
};
return msg;
